import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import Link from "next/link";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Activity,
  Dumbbell,
  Calendar,
  TrendingUp,
  Play,
} from "lucide-react";

export default async function DashboardPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) redirect("/login");

  const { data: profile } = await supabase
    .from("profiles")
    .select("full_name, username, physio_id")
    .eq("id", user.id)
    .single();

  // Fetch all active plans
  const { data: activePlans } = await supabase
    .from("workout_plans")
    .select(
      `
      id,
      name,
      description,
      created_at,
      plan_items (
        id,
        order,
        sets,
        reps,
        duration,
        rest_time,
        superset_group,
        exercises (
          id,
          name,
          category
        )
      )
    `
    )
    .eq("patient_id", user.id)
    .eq("active", true)
    .order("created_at", { ascending: false });

  // Fetch recent logs
  const { data: recentLogs } = await supabase
    .from("workout_logs")
    .select("id, completed_at, duration_seconds, feedback_score")
    .eq("patient_id", user.id)
    .order("completed_at", { ascending: false })
    .limit(7);

  const sessionsThisWeek =
    recentLogs?.filter((log) => {
      const logDate = new Date(log.completed_at);
      const weekAgo = new Date();
      weekAgo.setDate(weekAgo.getDate() - 7);
      return logDate >= weekAgo;
    }).length ?? 0;

  const lastSession = recentLogs?.[0];

  return (
    <div className="px-4 pt-6 space-y-6">
      {/* Welcome */}
      <div>
        <h1 className="text-2xl font-bold">
          Ciao,{" "}
          {profile?.username ?? profile?.full_name?.split(" ")[0] ?? ""}
        </h1>
        <p className="text-muted-foreground">Il tuo percorso di riabilitazione</p>
      </div>

      {/* Quick stats */}
      <div className="grid grid-cols-2 gap-3">
        <Card>
          <CardContent className="flex items-center gap-3 p-4">
            <div className="flex h-10 w-10 items-center justify-center rounded-full bg-teal-100">
              <Calendar className="h-5 w-5 text-teal-600" />
            </div>
            <div>
              <p className="text-2xl font-bold">{sessionsThisWeek}</p>
              <p className="text-xs text-muted-foreground">Questa settimana</p>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="flex items-center gap-3 p-4">
            <div className="flex h-10 w-10 items-center justify-center rounded-full bg-golden-100">
              <TrendingUp className="h-5 w-5 text-golden-600" />
            </div>
            <div>
              <p className="text-2xl font-bold">
                {lastSession
                  ? new Date(lastSession.completed_at).toLocaleDateString(
                      "it-IT",
                      {
                        day: "numeric",
                        month: "short",
                      }
                    )
                  : "--"}
              </p>
              <p className="text-xs text-muted-foreground">Ultima sessione</p>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Active plans */}
      {activePlans && activePlans.length > 0 ? (
        <div className="space-y-4">
          {activePlans.map((plan) => (
            <Card key={plan.id}>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <div>
                    <CardTitle className="flex items-center gap-2">
                      <Activity className="h-5 w-5 text-teal-600" />
                      {plan.name}
                    </CardTitle>
                    <CardDescription>
                      {plan.plan_items?.length ?? 0} esercizi
                    </CardDescription>
                  </div>
                  <Badge
                    variant="secondary"
                    className="bg-golden-100 text-golden-700"
                  >
                    Attiva
                  </Badge>
                </div>
              </CardHeader>
              <CardContent className="space-y-4">
                {/* Exercise list preview */}
                <div className="space-y-2">
                  {plan.plan_items
                    ?.sort((a: any, b: any) => a.order - b.order)
                    .slice(0, 4)
                    .map((item: any) => (
                      <div
                        key={item.id}
                        className="flex items-center justify-between rounded-lg bg-muted/50 px-3 py-2"
                      >
                        <div className="flex items-center gap-2">
                          <Dumbbell className="h-4 w-4 text-muted-foreground" />
                          <span className="text-sm font-medium">
                            {item.exercises?.name}
                          </span>
                        </div>
                        <span className="text-xs text-muted-foreground">
                          {item.sets}x
                          {item.reps
                            ? `${item.reps} rep`
                            : `${item.duration}s`}
                        </span>
                      </div>
                    ))}
                  {(plan.plan_items?.length ?? 0) > 4 && (
                    <p className="text-center text-xs text-muted-foreground">
                      +{(plan.plan_items?.length ?? 0) - 4} altri esercizi
                    </p>
                  )}
                </div>

                <Link
                  href={`/workout?planId=${plan.id}`}
                  className="block"
                >
                  <Button className="w-full gap-2" size="lg">
                    <Play className="h-5 w-5" />
                    Inizia Workout
                  </Button>
                </Link>
              </CardContent>
            </Card>
          ))}
        </div>
      ) : (
        <Card>
          <CardContent className="flex flex-col items-center gap-3 py-12">
            <div className="flex h-16 w-16 items-center justify-center rounded-full bg-muted">
              <Dumbbell className="h-8 w-8 text-muted-foreground" />
            </div>
            <p className="text-center text-muted-foreground">
              La tua fisioterapista non ha ancora assegnato una scheda
            </p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import { Header } from "@/components/layout/header";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { getPainColor } from "@/lib/utils/constants";
import { formatDuration } from "@/lib/utils/format-time";
import { Calendar, Clock, Dumbbell } from "lucide-react";

export default async function HistoryPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) redirect("/login");

  const { data: logs } = await supabase
    .from("workout_logs")
    .select(
      `
      id,
      started_at,
      completed_at,
      duration_seconds,
      exercises_completed,
      total_sets_completed,
      feedback_score,
      feedback_notes,
      workout_plans (
        name
      )
    `
    )
    .eq("patient_id", user.id)
    .order("completed_at", { ascending: false });

  return (
    <div>
      <Header title="Storico sessioni" />
      <div className="px-4 pt-4 space-y-3">
        {!logs?.length ? (
          <div className="flex flex-col items-center gap-3 py-20">
            <div className="flex h-16 w-16 items-center justify-center rounded-full bg-muted">
              <Clock className="h-8 w-8 text-muted-foreground" />
            </div>
            <p className="text-muted-foreground">Nessuna sessione completata</p>
          </div>
        ) : (
          logs.map((log) => {
            const date = new Date(log.completed_at);
            const painColor = log.feedback_score
              ? getPainColor(log.feedback_score)
              : "";

            return (
              <Card key={log.id}>
                <CardContent className="p-4">
                  <div className="flex items-start justify-between">
                    <div className="space-y-1">
                      <p className="font-semibold">
                        {(log as any).workout_plans?.name ?? "Sessione"}
                      </p>
                      <div className="flex items-center gap-1 text-sm text-muted-foreground">
                        <Calendar className="h-3.5 w-3.5" />
                        {date.toLocaleDateString("it-IT", {
                          weekday: "short",
                          day: "numeric",
                          month: "short",
                        })}
                      </div>
                    </div>
                    {log.feedback_score && (
                      <Badge className={painColor} variant="secondary">
                        Dolore: {log.feedback_score}/10
                      </Badge>
                    )}
                  </div>

                  <div className="mt-3 flex gap-4 text-sm text-muted-foreground">
                    {log.duration_seconds && (
                      <div className="flex items-center gap-1">
                        <Clock className="h-3.5 w-3.5" />
                        {formatDuration(log.duration_seconds)}
                      </div>
                    )}
                    {log.exercises_completed && (
                      <div className="flex items-center gap-1">
                        <Dumbbell className="h-3.5 w-3.5" />
                        {log.exercises_completed} esercizi
                      </div>
                    )}
                  </div>

                  {log.feedback_notes && (
                    <p className="mt-2 text-sm italic text-muted-foreground">
                      &quot;{log.feedback_notes}&quot;
                    </p>
                  )}
                </CardContent>
              </Card>
            );
          })
        )}
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Header } from "@/components/layout/header";
import { DailySummaryCard } from "@/components/nutrition/daily-summary-card";
import { MealSection } from "@/components/nutrition/meal-section";
import { Button } from "@/components/ui/button";
import { MEAL_SLOTS, type MealSlot, type DayType } from "@/types/nutrition";
import { cn } from "@/lib/utils";
import { Loader2 } from "lucide-react";

interface LogEntry {
  id: string;
  meal_slot: string;
  recipe_id: string | null;
  custom_name: string | null;
  protein_grams: number;
  carbs_grams: number;
  fats_grams: number;
  calories: number;
  recipes?: { name: string } | null;
}

export default function NutritionPage() {
  const [dayType, setDayType] = useState<DayType>("workout");
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [budget, setBudget] = useState({ workout: 2100, rest: 1900 });
  const [loading, setLoading] = useState(true);

  const today = new Date().toISOString().split("T")[0];

  const fetchData = useCallback(async () => {
    const supabase = createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) return;

    const [logsRes, budgetRes] = await Promise.all([
      supabase
        .from("nutrition_logs")
        .select("*, recipes(name)")
        .eq("patient_id", user.id)
        .eq("date", today),
      supabase
        .from("calorie_budgets")
        .select("*")
        .eq("patient_id", user.id)
        .maybeSingle(),
    ]);

    if (logsRes.data) setLogs(logsRes.data as LogEntry[]);
    if (budgetRes.data) {
      setBudget({
        workout: budgetRes.data.workout_day_calories,
        rest: budgetRes.data.rest_day_calories,
      });
    }
    setLoading(false);
  }, [today]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleRemove = useCallback(
    async (logId: string) => {
      const supabase = createClient();
      const { error } = await supabase.from("nutrition_logs").delete().eq("id", logId);
      if (error) {
        alert("Errore nell'eliminazione del pasto");
        return;
      }
      setLogs((prev) => prev.filter((l) => l.id !== logId));
    },
    []
  );

  const totalCalories = logs.reduce((sum, l) => sum + l.calories, 0);
  const totalProtein = logs.reduce((sum, l) => sum + Number(l.protein_grams), 0);
  const totalCarbs = logs.reduce((sum, l) => sum + Number(l.carbs_grams), 0);
  const totalFats = logs.reduce((sum, l) => sum + Number(l.fats_grams), 0);
  const currentBudget = dayType === "workout" ? budget.workout : budget.rest;

  if (loading) {
    return (
      <div className="flex min-h-[60vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-teal-500" />
      </div>
    );
  }

  return (
    <div>
      <Header title="Nutrizione" />
      <div className="px-4 pt-4 space-y-4">
        {/* Day type toggle */}
        <div className="flex gap-2">
          {(["workout", "rest"] as const).map((type) => (
            <Button
              key={type}
              variant={dayType === type ? "default" : "outline"}
              size="sm"
              onClick={() => setDayType(type)}
              className={cn(
                "flex-1",
                dayType === type && "bg-teal-600 hover:bg-teal-700"
              )}
            >
              {type === "workout" ? "Giorno allenamento" : "Giorno riposo"}
            </Button>
          ))}
        </div>

        <DailySummaryCard
          consumed={totalCalories}
          budget={currentBudget}
          proteinGrams={Math.round(totalProtein)}
          carbsGrams={Math.round(totalCarbs)}
          fatsGrams={Math.round(totalFats)}
        />

        {MEAL_SLOTS.map(({ key, label }) => {
          const slotLogs = logs.filter((l) => l.meal_slot === key);
          const meals = slotLogs.map((l) => ({
            id: l.id,
            name: l.recipes?.name ?? l.custom_name ?? "Pasto",
            calories: l.calories,
            proteinGrams: Number(l.protein_grams),
            carbsGrams: Number(l.carbs_grams),
            fatsGrams: Number(l.fats_grams),
          }));

          return (
            <MealSection
              key={key}
              slot={key}
              label={label}
              meals={meals}
              dayType={dayType}
              onRemove={handleRemove}
            />
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Sun, Moon } from "lucide-react";
import { cn } from "@/lib/utils";

export function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => setMounted(true), []);

  if (!mounted) return null;

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-lg">Tema</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="flex gap-2">
          <Button
            variant="outline"
            size="lg"
            onClick={() => setTheme("light")}
            className={cn(
              "flex-1 gap-2",
              theme === "light" &&
                "border-teal-500 bg-teal-50 text-teal-700 dark:bg-teal-900 dark:text-teal-300"
            )}
          >
            <Sun className="h-5 w-5" />
            Chiaro
          </Button>
          <Button
            variant="outline"
            size="lg"
            onClick={() => setTheme("dark")}
            className={cn(
              "flex-1 gap-2",
              theme === "dark" &&
                "border-teal-500 bg-teal-50 text-teal-700 dark:bg-teal-900 dark:text-teal-300"
            )}
          >
            <Moon className="h-5 w-5" />
            Scuro
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

