"use client";

import { Suspense, useEffect, useRef, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { useWorkoutStore } from "@/lib/stores/workout-store";
import { WorkoutPlayer } from "@/components/workout/workout-player";
import type { PlanItemWithExercise } from "@/types/workout";
import { Loader2 } from "lucide-react";

export default function WorkoutPage() {
  return (
    <Suspense
      fallback={
        <div className="flex min-h-[60vh] items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-teal-500" />
        </div>
      }
    >
      <WorkoutPageContent />
    </Suspense>
  );
}

function WorkoutPageContent() {
  const router = useRouter();
  const searchParams = useSearchParams();

  // Individual selectors — avoid subscribing to the entire store
  const phase = useWorkoutStore((s) => s.phase);
  const storePlanId = useWorkoutStore((s) => s.planId);
  const loadPlanAction = useWorkoutStore((s) => s.loadPlan);
  const reset = useWorkoutStore((s) => s.reset);

  const [loading, setLoading] = useState(true);
  const loadingRef = useRef(false);

  const planIdParam = searchParams.get("planId");

  useEffect(() => {
    // If resuming the SAME plan (e.g., coming back from background), skip fetch
    if (phase !== "idle" && storePlanId && storePlanId === planIdParam) {
      setLoading(false);
      return;
    }

    // If store has a different plan, reset before loading new one.
    // Return so the effect re-runs cleanly with phase="idle".
    if (phase !== "idle" && storePlanId !== planIdParam) {
      reset();
      return;
    }

    // Guard against double-invocation (React Strict Mode / hydration races)
    if (loadingRef.current) return;

    async function fetchAndLoadPlan() {
      loadingRef.current = true;
      const supabase = createClient();
      const {
        data: { user },
      } = await supabase.auth.getUser();

      if (!user) {
        loadingRef.current = false;
        router.push("/login");
        return;
      }

      let query = supabase
        .from("workout_plans")
        .select(
          `
          id,
          name,
          plan_items (
            id,
            order,
            sets,
            reps,
            duration,
            rest_time,
            rest_after,
            notes,
            superset_group,
            transition_rest,
            exercises (
              id,
              name,
              description,
              category,
              video_url
            )
          )
        `
        )
        .eq("patient_id", user.id);

      if (planIdParam) {
        query = query.eq("id", planIdParam);
      } else {
        query = query.eq("active", true).limit(1);
      }

      const { data: plans } = await query;
      const plan = plans?.[0];

      if (!plan || !plan.plan_items?.length) {
        loadingRef.current = false;
        router.push("/dashboard");
        return;
      }

      const items: PlanItemWithExercise[] = plan.plan_items
        .filter((pi: any) => pi.exercises != null)
        .map((pi: any) => ({
          id: pi.id,
          exercise: pi.exercises,
          sets: pi.sets,
          reps: pi.reps,
          duration: pi.duration,
          rest_time: pi.rest_time,
          rest_after: pi.rest_after,
          order: pi.order,
          notes: pi.notes,
          superset_group: pi.superset_group,
          transition_rest: pi.transition_rest,
        }));

      if (!items.length) {
        loadingRef.current = false;
        router.push("/dashboard");
        return;
      }

      loadPlanAction(plan.id, plan.name, items);
      loadingRef.current = false;
      setLoading(false);
    }

    fetchAndLoadPlan();
  }, [phase, storePlanId, planIdParam, router, loadPlanAction, reset]);

  if (loading) {
    return (
      <div className="flex min-h-[60vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-teal-500" />
      </div>
    );
  }

  return <WorkoutPlayer />;
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";

function revalidatePhysio() {
  revalidatePath("/physio/dashboard");
  revalidatePath("/physio/plans");
}

export async function togglePlanActive(planId: string, active: boolean) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Non autenticato");

  const { error } = await supabase
    .from("workout_plans")
    .update({ active })
    .eq("id", planId)
    .eq("physio_id", user.id);

  if (error) throw new Error("Errore nell'aggiornamento della scheda");

  revalidatePhysio();
}

export async function deletePlan(planId: string) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Non autenticato");

  const { error } = await supabase
    .from("workout_plans")
    .delete()
    .eq("id", planId)
    .eq("physio_id", user.id);

  if (error) throw new Error("Errore nell'eliminazione della scheda");

  revalidatePhysio();
}

export async function duplicatePlan(planId: string) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Non autenticato");

  // Get the original plan
  const { data: plan } = await supabase
    .from("workout_plans")
    .select("*, plan_items(*)")
    .eq("id", planId)
    .eq("physio_id", user.id)
    .single();

  if (!plan) throw new Error("Scheda non trovata");

  // Create duplicated plan
  const { data: newPlan, error: planError } = await supabase
    .from("workout_plans")
    .insert({
      name: `${plan.name} (copia)`,
      description: plan.description,
      patient_id: plan.patient_id,
      physio_id: user.id,
      active: false,
    })
    .select()
    .single();

  if (planError || !newPlan) throw new Error("Errore nella duplicazione della scheda");

  // Copy plan items
  if (plan.plan_items?.length) {
    const newItems = plan.plan_items.map(
      ({ id, plan_id, created_at, ...item }: Record<string, unknown>) => ({
        ...item,
        plan_id: newPlan.id,
      })
    );

    const { error: itemsError } = await supabase
      .from("plan_items")
      .insert(newItems);

    if (itemsError) throw new Error("Errore nella copia degli esercizi");
  }

  revalidatePhysio();
}

