"use client";

import { useCallback, useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Header } from "@/components/layout/header";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { INVITE_CODE_LENGTH, INVITE_CODE_EXPIRY_DAYS } from "@/lib/utils/constants";
import { Copy, KeyRound, Loader2, Plus, Check } from "lucide-react";

function generateCode(): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"; // No 0,O,1,I for readability
  let code = "";
  for (let i = 0; i < INVITE_CODE_LENGTH; i++) {
    code += chars[Math.floor(Math.random() * chars.length)];
  }
  return code;
}

interface InviteCode {
  id: string;
  code: string;
  used_by: string | null;
  used_at: string | null;
  expires_at: string;
  created_at: string;
}

export default function InvitePage() {
  const [codes, setCodes] = useState<InviteCode[]>([]);
  const [loading, setLoading] = useState(true);
  const [creating, setCreating] = useState(false);
  const [copiedCode, setCopiedCode] = useState<string | null>(null);

  const fetchCodes = useCallback(async () => {
    const supabase = createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) return;

    const { data } = await supabase
      .from("invite_codes")
      .select("*")
      .eq("physio_id", user.id)
      .order("created_at", { ascending: false });

    if (data) setCodes(data);
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchCodes();
  }, [fetchCodes]);

  const handleCreate = useCallback(async () => {
    setCreating(true);
    const supabase = createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) return;

    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + INVITE_CODE_EXPIRY_DAYS);

    const { data, error } = await supabase
      .from("invite_codes")
      .insert({
        code: generateCode(),
        physio_id: user.id,
        expires_at: expiresAt.toISOString(),
      })
      .select()
      .single();

    if (error) {
      alert("Errore nella generazione del codice");
      setCreating(false);
      return;
    }

    if (data) setCodes((prev) => [data, ...prev]);
    setCreating(false);
  }, []);

  const handleCopy = useCallback((code: string) => {
    navigator.clipboard.writeText(code);
    setCopiedCode(code);
    setTimeout(() => setCopiedCode(null), 2000);
  }, []);

  return (
    <div>
      <Header title="Codice invito" />
      <div className="px-4 pt-4 lg:px-0 lg:pt-0 space-y-4">
        <p className="text-sm text-muted-foreground">
          Genera un codice invito per collegare il tuo paziente. Il codice scade
          dopo {INVITE_CODE_EXPIRY_DAYS} giorni.
        </p>

        <Button
          onClick={handleCreate}
          disabled={creating}
          className="w-full gap-2"
        >
          {creating ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Plus className="h-4 w-4" />
          )}
          Genera nuovo codice
        </Button>

        {loading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-teal-500" />
          </div>
        ) : codes.length === 0 ? (
          <div className="flex flex-col items-center gap-3 py-12">
            <KeyRound className="h-10 w-10 text-muted-foreground" />
            <p className="text-muted-foreground">Nessun codice generato</p>
          </div>
        ) : (
          <div className="space-y-3">
            {codes.map((invite) => {
              const isExpired = new Date(invite.expires_at) < new Date();
              const isUsed = !!invite.used_by;

              return (
                <Card key={invite.id}>
                  <CardContent className="flex items-center justify-between p-4">
                    <div className="space-y-1">
                      <p className="font-mono text-2xl font-bold tracking-[0.3em]">
                        {invite.code}
                      </p>
                      <div className="flex items-center gap-2">
                        {isUsed ? (
                          <Badge className="bg-golden-100 text-golden-700">
                            Usato
                          </Badge>
                        ) : isExpired ? (
                          <Badge variant="destructive">Scaduto</Badge>
                        ) : (
                          <Badge variant="secondary">Attivo</Badge>
                        )}
                        <span className="text-xs text-muted-foreground">
                          Scade:{" "}
                          {new Date(invite.expires_at).toLocaleDateString(
                            "it-IT"
                          )}
                        </span>
                      </div>
                    </div>
                    {!isUsed && !isExpired && (
                      <Button
                        variant="outline"
                        size="icon"
                        onClick={() => handleCopy(invite.code)}
                      >
                        {copiedCode === invite.code ? (
                          <Check className="h-4 w-4 text-golden-600" />
                        ) : (
                          <Copy className="h-4 w-4" />
                        )}
                      </Button>
                    )}
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { Header } from "@/components/layout/header";
import { PlanEditor, type PlanItem } from "@/components/physio/plan-editor";
import { Loader2 } from "lucide-react";

function generateTempId() {
  return Math.random().toString(36).substring(2, 9);
}

export default function EditPlanPage() {
  const params = useParams<{ planId: string }>();
  const [patientId, setPatientId] = useState<string | null>(null);
  const [initialPlan, setInitialPlan] = useState<{
    name: string;
    description: string;
    items: PlanItem[];
  } | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      const supabase = createClient();
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) return;

      const { data: plan } = await supabase
        .from("workout_plans")
        .select(
          `
          id, name, description, patient_id,
          plan_items (
            id, exercise_id, "order", sets, reps, duration,
            rest_time, rest_after, notes, superset_group, transition_rest,
            exercises (id, name)
          )
        `
        )
        .eq("id", params.planId)
        .eq("physio_id", user.id)
        .single();

      if (!plan) {
        setLoading(false);
        return;
      }

      setPatientId(plan.patient_id);

      const loadedItems: PlanItem[] = (plan.plan_items ?? [])
        .sort((a: any, b: any) => a.order - b.order)
        .map((pi: any) => ({
          tempId: generateTempId(),
          exerciseId: pi.exercise_id,
          exerciseName: pi.exercises?.name ?? "",
          type: pi.duration ? ("timed" as const) : ("reps" as const),
          sets: pi.sets,
          reps: pi.reps ?? 10,
          duration: pi.duration ?? 30,
          restTime: pi.rest_time,
          restAfter: pi.rest_after ?? 90,
          notes: pi.notes ?? "",
          supersetGroup: pi.superset_group,
          transitionRest: pi.transition_rest ?? 10,
        }));

      setInitialPlan({
        name: plan.name,
        description: plan.description ?? "",
        items: loadedItems,
      });
      setLoading(false);
    }
    load();
  }, [params.planId]);

  if (loading) {
    return (
      <div className="flex min-h-[60vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-teal-500" />
      </div>
    );
  }

  if (!patientId || !initialPlan) {
    return (
      <div>
        <Header title="Modifica scheda" />
        <div className="px-4 pt-8 text-center text-muted-foreground">
          Scheda non trovata
        </div>
      </div>
    );
  }

  return (
    <div>
      <Header title="Modifica scheda" />
      <PlanEditor
        mode="edit"
        planId={params.planId}
        patientId={patientId}
        initialPlan={initialPlan}
      />
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import Link from "next/link";
import { Header } from "@/components/layout/header";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  TogglePlanButton,
  DeletePlanButton,
  DuplicatePlanButton,
} from "@/components/physio/plan-actions";
import { Dumbbell, Pencil, Plus } from "lucide-react";

export default async function PlansPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect("/login");

  // Get linked patient
  const { data: patient } = await supabase
    .from("profiles")
    .select("id, full_name")
    .eq("physio_id", user.id)
    .eq("role", "patient")
    .limit(1)
    .maybeSingle();

  if (!patient) {
    return (
      <div>
        <Header title="Schede" />
        <div className="px-4 pt-4 lg:px-0 lg:pt-0">
          <div className="flex flex-col items-center gap-4 py-20">
            <Dumbbell className="h-10 w-10 text-muted-foreground" />
            <p className="text-center text-muted-foreground">
              Collega un paziente per creare schede di allenamento.
            </p>
            <Link href="/physio/settings">
              <Button variant="outline">Genera codice invito</Button>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  const { data: plans } = await supabase
    .from("workout_plans")
    .select("id, name, description, active, created_at, plan_items(id)")
    .eq("patient_id", patient.id)
    .order("created_at", { ascending: false });

  return (
    <div>
      <Header title="Schede" />
      <div className="px-4 pt-4 lg:px-0 lg:pt-0 space-y-4">
        {/* Top bar */}
        <div className="flex items-center justify-between">
          <p className="text-sm text-muted-foreground">
            Schede per <span className="font-medium text-foreground">{patient.full_name}</span>
          </p>
          <Link href="/physio/plans/new">
            <Button size="sm" className="gap-1.5">
              <Plus className="h-4 w-4" />
              Nuova scheda
            </Button>
          </Link>
        </div>

        {/* Plans list */}
        {!plans?.length ? (
          <Card>
            <CardContent className="flex flex-col items-center gap-3 py-12">
              <Dumbbell className="h-8 w-8 text-muted-foreground" />
              <p className="text-sm text-muted-foreground">
                Nessuna scheda creata. Crea la prima scheda di allenamento.
              </p>
              <Link href="/physio/plans/new">
                <Button size="sm" className="gap-1.5">
                  <Plus className="h-4 w-4" />
                  Crea scheda
                </Button>
              </Link>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-3">
            {plans.map((plan) => (
              <Card key={plan.id}>
                <CardContent className="p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div className="space-y-1 min-w-0 flex-1">
                      <div className="flex items-center gap-2">
                        <p className="font-medium truncate">{plan.name}</p>
                        {plan.active && (
                          <Badge className="bg-golden-100 text-golden-700 shrink-0">
                            Attiva
                          </Badge>
                        )}
                      </div>
                      {plan.description && (
